#include <stdio.h>
#include <math.h>
int main(){
    int t; if(scanf("%d", &t)!=1) return 0;
    while(t--){
        double P,S; if(scanf("%lf %lf", &P, &S)!=2) break;
        double L = P/4.0;
        double M = S/2.0;
        double D = sqrt(L*L - 3.0*M);
        double V = ((L - D)*(L - D)*(L + 2.0*D))/27.0;
        printf("%.2f\n", V);
    }
    return 0;
}

